fn send_to_backend(
    mut req: Request,
    backend_config: &BackendConfig,
) -> Result<Response, Error> {
    let original_host = req
        .get_header_str(header::HOST)
        .unwrap_or("")
        .to_string();

    req.set_header(header::HOST, &backend_config.host);

    if backend_config.sni_hostname.is_none() && backend_config.use_ssl {
        req.set_header("X-Original-Host", original_host);
    }

    match req.send(&backend_config.name) {
        Ok(mut resp) => {
            resp.set_header("X-Served-By", "Fastly-Compute@Edge");
            resp.set_header("X-Backend", &backend_config.name);
            Ok(resp)
        }
        Err(e) => {
            eprintln!("Backend error for {}: {:?}", backend_config.name, e);
            Ok(Response::from_status(StatusCode::BAD_GATEWAY)
                .with_body_text_plain(&format!(
                    "Backend {} is currently unavailable",
                    backend_config.name
                )))
        }
    }
}

